const d = $input.first().json;
const list = d.search_item_list || [];
let rows = list.map(it => {
  const a = it.aweme_info || {};
  const st = a.statistics || {};
  const au = a.author || {};
  return {
    desc: (a.desc || '').trim(),
    views: st.play_count || 0,
    likes: st.digg_count || 0,
    author: au.nickname || au.unique_id || '',
    uniq: au.unique_id || '',
    id: a.aweme_id || ''
  };
}).filter(r => r.desc).sort((x,y)=>y.views-x.views);
const top = rows.slice(0, $('Config').first().json.top_n || 6);
const now = new Date().toISOString();
const query = $('Config').first().json.query;
const rt = v => ({ rich_text:[{ text:{ content:String(v==null?'':v).slice(0,1900) } }] });
return top.map(r => {
  const url = (r.uniq && r.id) ? ('https://www.tiktok.com/@'+r.uniq+'/video/'+r.id) : '';
  const props = {
    'post': { title:[{ text:{ content:(r.desc||'(no desc)').slice(0,1900) } }] },
    'platform': { select:{ name:'tiktok' } },
    'query': rt(query),
    'author': rt(r.author),
    'views': { number: r.views },
    'likes': { number: r.likes },
    'collected_at': { date:{ start: now } }
  };
  if (/^https?:\/\//.test(url)) props['url'] = { url };
  return { json: { author: r.author, views: r.views, desc: r.desc, notion_props: props } };
});
